from flask import Flask, request, jsonify
from flask_jwt import JWTManager, jwt_required
import datetime
import hashlib
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
jwt = JWTManager(app)

def authenticate(username, password):
    with open('users.txt', 'r') as file:
        for line in file:
            user, hashed_pass = line.split(':')
            if user == username and hashlib.sha256(password.encode()).hexdigest() == hashed_pass:
                return True
    return False

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        return jsonify({'error': 'Missing credentials'}), 401

    if authenticate(auth.username, auth.password):
        token = jwt.encode({'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30)}, app.config['SECRET_KEY'])
        return jsonify({'token': token.decode('UTF-8')})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
@jwt_required()
def protected():
    return jsonify({'message': 'Protected data'})

if __name__ == '__main__':
    app.run(debug=True)